#include <stdio.h>
int maxSum(int arr[], int n, int k) {
    int max_sum = 0;
    for (int i = 0; i < n; i++) {
        int sum = 0;
        for (int j = i; j < n; j++) {
            sum += arr[j];
            if (sum % k == 0) {
                max_sum = (max_sum > sum) ? max_sum : sum;
            }
        }
    }
    return max_sum;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", maxSum(arr, n, k));
    }
    return 0;
}

